   207→	if !ok {
   208→		return false
   209→	}
   210→
   211→	file = strings.TrimPrefix(file, rootPath)
   212→	for _, lp := range logLevels {
   213→		if strings.HasPrefix(file, lp.path) {
   214→			return lp.level >= requiredLevel
   215→		}
   216→	}
   217→	return false
