   220→func parseArgs(args []interface{}) (*logrus.Entry, string) {
   221→	var l *logrus.Entry
   222→	var err error
   223→	if args[0] == nil {
   224→		l = createNewLogger()
   225→		args = args[1:]
   226→	} else {
   227→		l, err = extractLogger(args[0])
   228→		if err != nil {
   229→			l = createNewLogger()
   230→		} else {
   231→			args = args[1:]
   232→		}
   233→	}
   234→	if len(args) > 1 {
   235→		kvPairs := args[1:]
   236→		l = addFields(l, kvPairs)
   237→	}
   238→	if logSourceLine {
   239→		_, file, line, ok := runtime.Caller(3)
   240→		if !ok {
   241→			file = "???"
   242→			line = 0
   243→		}
   244→		//_, filename := path.Split(file)
   245→		//l = l.WithField("filename", filename).WithField("line", line)
   246→		l = l.WithField(" source", fmt.Sprintf("file://%s:%d", file, line))
   247→	}
   248→
   249→	switch msg := args[0].(type) {
   250→	case error:
   251→		return l, msg.Error()
   252→	case string:
   253→		return l, msg
   254→	}
   255→
   256→	return l, ""
   257→}
   258→
   259→func addFields(logger *logrus.Entry, keyValuePairs []interface{}) *logrus.Entry {
   260→	for i := 0; i < len(keyValuePairs); i += 2 {
   261→		switch name := keyValuePairs[i].(type) {
   262→		case error:
   263→			logger = logger.WithField("error", name.Error())
   264→		case string:
   265→			if i+1 >= len(keyValuePairs) {
   266→				logger = logger.WithField(name, "!!!!Invalid number of arguments in log call!!!!")
   267→			} else {
   268→				switch v := keyValuePairs[i+1].(type) {
   269→				case time.Duration:
