   271→				case fmt.Stringer:
   272→					vOf := reflect.ValueOf(v)
   273→					if vOf.Kind() == reflect.Pointer && vOf.IsNil() {
   274→						logger = logger.WithField(name, "nil")
   275→					} else {
   276→						logger = logger.WithField(name, v.String())
   277→					}
   278→				default:
   279→					logger = logger.WithField(name, v)
   280→				}
   281→			}
   282→		}
   283→	}
