package log

import (
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
)

func TestWindowsLineEndingsHook(t *testing.T) {
	tests := []struct {
		name     string
		input    string
		expected string
	}{
		{
			name:     "converts single LF to CRLF",
			input:    "Hello\nWorld",
			expected: "Hello\r\nWorld",
		},
		{
			name:     "preserves existing CRLF",
			input:    "Hello\r\nWorld",
			expected: "Hello\r\nWorld",
		},
		{
			name:     "converts multiple LF to CRLF",
			input:    "Line1\nLine2\nLine3",
			expected: "Line1\r\nLine2\r\nLine3",
		},
		{
			name:     "handles mixed CRLF and LF",
			input:    "Line1\r\nLine2\nLine3",
			expected: "Line1\r\nLine2\r\nLine3",
		},
		{
			name:     "no double conversion of CRLF",
			input:    "Hello\r\nWorld\nEnd",
			expected: "Hello\r\nWorld\r\nEnd",
		},
		{
			name:     "empty string",
			input:    "",
			expected: "",
		},
		{
			name:     "no newlines",
			input:    "Hello World",
			expected: "Hello World",
		},
		{
			name:     "trailing LF",
			input:    "Hello\n",
			expected: "Hello\r\n",
		},
		{
			name:     "trailing CRLF",
			input:    "Hello\r\n",
			expected: "Hello\r\n",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := normalizeLineEndings(tt.input)
			assert.Equal(t, tt.expected, result)
		})
	}
}

func TestWindowsLineEndingsHookWithEntry(t *testing.T) {
	hook := &WindowsLineEndingHook{}

	t.Run("converts message line endings", func(t *testing.T) {
		entry := &logrus.Entry{
			Message: "Hello\nWorld",
		}
		err := hook.Fire(entry)
		assert.Nil(t, err)
		assert.Equal(t, "Hello\r\nWorld", entry.Message)
	})

	t.Run("preserves CRLF in message", func(t *testing.T) {
		entry := &logrus.Entry{
			Message: "Hello\r\nWorld",
		}
		err := hook.Fire(entry)
		assert.Nil(t, err)
		assert.Equal(t, "Hello\r\nWorld", entry.Message)
	})

	t.Run("converts line endings in data fields", func(t *testing.T) {
		entry := &logrus.Entry{
			Message: "Error occurred",
			Data: logrus.Fields{
				"details": "Stack\ntrace\nhere",
			},
		}
		err := hook.Fire(entry)
		assert.Nil(t, err)
		assert.Equal(t, "Stack\r\ntrace\r\nhere", entry.Data["details"])
	})

	t.Run("handles multiple data fields", func(t *testing.T) {
		entry := &logrus.Entry{
			Message: "Error\noccurred",
			Data: logrus.Fields{
				"details": "First\nfield",
				"trace":   "Second\nfield",
			},
		}
		err := hook.Fire(entry)
		assert.Nil(t, err)
		assert.Equal(t, "Error\r\noccurred", entry.Message)
		assert.Equal(t, "First\r\nfield", entry.Data["details"])
		assert.Equal(t, "Second\r\nfield", entry.Data["trace"])
	})
}

